#!/usr/bin/env tsx
/**
 * Generates Zod schemas from docs/specs/schemas/*.schema.json.
 *
 * Runs on postinstall + prebuild. Generated files land in lib/schema/
 * (gitignored). If `npm ci --ignore-scripts` is used, run
 * `npm run gen-zod` manually before `npm test` / `tsc`.
 *
 * The output is intentionally permissive: we transform raw JSON Schema
 * to Zod via `json-schema-to-zod`, then write each schema as a named
 * export. The Zod schemas validate shape only — referential checks
 * (e.g., does the scenario exist?) happen at write/save time and at
 * read time when computing the "blocked" indicator.
 */
import fs from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import { jsonSchemaToZod } from 'json-schema-to-zod';

const here = path.dirname(fileURLToPath(import.meta.url));
const appRoot = path.resolve(here, '..');
const repoRoot = path.resolve(appRoot, '..', '..');
const schemasDir = path.join(repoRoot, 'docs', 'specs', 'schemas');
const outDir = path.join(appRoot, 'lib', 'schema');

const SCHEMAS = [
  { file: 'unit-test.schema.json', name: 'UnitTestSchema', out: 'unit-test.ts' },
  { file: 'ann.schema.json', name: 'AnnotationSchema', out: 'annotation.ts' },
  { file: 'run-log.schema.json', name: 'RunLogSchema', out: 'run-log.ts' },
  { file: 'mcp-fixture.schema.json', name: 'McpFixtureSchema', out: 'mcp-fixture.ts' },
];

async function main(): Promise<void> {
  await fs.mkdir(outDir, { recursive: true });

  for (const { file, name, out } of SCHEMAS) {
    const inputPath = path.join(schemasDir, file);
    let raw: string;
    try {
      raw = await fs.readFile(inputPath, 'utf8');
    } catch (err) {
      // If running before schemas exist (rare), skip rather than fail.
      console.warn(`[gen-zod] Skipping ${file}: ${(err as Error).message}`);
      continue;
    }

    let parsed: unknown;
    try {
      parsed = JSON.parse(raw);
    } catch (err) {
      throw new Error(`[gen-zod] Could not parse ${inputPath}: ${(err as Error).message}`);
    }

    // json-schema-to-zod returns a string of valid TypeScript/JS that
    // evaluates to a Zod schema, using imports from 'zod'.
    const zodSource = jsonSchemaToZod(parsed, { module: 'esm', name });

    const header = `// AUTOGENERATED — do not edit by hand.\n// Source: docs/specs/schemas/${file}\n// Regenerate via: npm run gen-zod\n\n`;
    const outPath = path.join(outDir, out);
    await fs.writeFile(outPath, header + zodSource, 'utf8');
    // eslint-disable-next-line no-console
    console.log(`[gen-zod] wrote ${path.relative(appRoot, outPath)}`);
  }
}

main().catch((err) => {
  // eslint-disable-next-line no-console
  console.error(err);
  process.exit(1);
});
